{"code": "import json

# Get the data from previous query
history_data = var_functions.query_db:16

# Transform string with proper JSON format
try:
    # The data might be a string representation, try to parse it
    if isinstance(history_data, str):
        history_data = json.loads(history_data)
except:
    pass

# Initialize dictionaries to track metrics
transfer_counts = {}  # transfers FROM an agent
cases_handled = {}    # cases handled by an agent (initial assignment or transfer TO)

# Process each record
for record in history_data:
    old_owner = record.get('oldvalue__c')
    new_owner = record.get('newvalue__c')
    case_id = record.get('case_id')

    # Count cases handled by agent (both initial and transfers TO)
    if new_owner and new_owner != 'None':
        cases_handled[new_owner] = cases_handled.get(new_owner, 0) + 1

    # Count transfers FROM agent (only when old_owner is not 'None')
    if old_owner and old_owner != 'None':
        transfer_counts[old_owner] = transfer_counts.get(old_owner, 0) + 1

# Filter agents who handled more than 0 cases
eligible_agents = {agent_id: {
    'transfers': transfer_counts.get(agent_id, 0),
    'cases': cases_handled.get(agent_id, 0)
} for agent_id in cases_handled if cases_handled.get(agent_id, 0) > 0}

# Find agent with fewest transfers
if eligible_agents:
    sorted_agents = sorted(eligible_agents.items(), key=lambda x: (x[1]['transfers'], x[0]))
    agent_with_fewest_transfers = sorted_agents[0]
    result = agent_with_fewest_transfers[0]
else:
    result = "No agents found"

# Print in required format
print('__RESULT__:')
print(json.dumps(result))"}

